def create_token(payload: Dict[str, Any], algorithm: str = 'HS256', expires_in: int = 3600) -> str:
    if algorithm in ['HS256', 'HS384', 'HS512']:
        return create_access_token(identity=payload, expires_delta=expires_in)
    else:
        # For RS256 and others, use jose library
        from jose import jwt
        secret = os.environ.get('JWT_SECRET_KEY')
        if not secret:
            raise ValueError("JWT_SECRET_KEY not configured")
        return jwt.encode(payload, secret, algorithm=algorithm)

